import React, { useContext } from "react";
import { Link, graphql } from "gatsby";
import Layout, { LangContext } from "../components/Layout";
import SEO from "../components/SEO";
import DataPanel from "../components/DataPanel";
import { pickLangNodes, langSlug } from "../utils/i18n";

const MarketsPage = ({ data }) => {
  const { lang } = useContext(LangContext);
  const reports = pickLangNodes(data.allMarkdownRemark.nodes, lang);
  const catalyst = pickLangNodes(data.catalyst.nodes, lang);
  const latest = reports[0];

  const l = (vi, en) => lang === "vi" ? vi : en;
  const title = l("📈 Thị trường & Tình báo", "📈 Markets & Intel");
  const subtitle = l("Tình báo thị trường crypto toàn cầu & tín hiệu vĩ mô", "Global crypto intelligence & macro signals");
  const viewFull = l("Xem báo cáo đầy đủ →", "View full report →");
  const latestLabel = l("🌐 Mới nhất: Tình báo Crypto Toàn cầu", "🌐 Latest: Global Crypto Intelligence");
  const recentCrypto = l("📋 Báo cáo Crypto gần đây", "📋 Recent Crypto Reports");
  const recentCatalyst = l("⚡ Báo cáo Catalyst gần đây", "⚡ Recent Catalyst Reports");
  const noReport = l("Chưa có báo cáo.", "No report available.");

  return (
    <Layout>
      <div className="page-header">
        <h1>{title}</h1>
        <p className="page-subtitle">{subtitle}</p>
      </div>

      <div className="markets-grid">
        <DataPanel title={`${latestLabel} — ${latest?.fields?.date || ""}`}>
          <div className="report-content markdown-body">
            <div dangerouslySetInnerHTML={{ __html: latest?.html || `<p>${noReport}</p>` }} />
          </div>
          {latest?.fields?.slug && (
            <Link to={langSlug(latest.fields.slug, lang)} className="view-all" style={{ marginTop: "12px", display: "inline-block" }}>
              {viewFull}
            </Link>
          )}
        </DataPanel>

        <div className="side-panels">
          <DataPanel title={recentCrypto}>
            <div className="report-list">
              {reports.slice(0, 8).map((report) => (
                <Link key={report.id} to={langSlug(report.fields?.slug || "/", lang)} className="report-list-item">
                  <span className="report-date">{report.fields?.date || "—"}</span>
                  <span className="report-title">
                    {report.fields?.inferredTitle || "Crypto Report"}
                  </span>
                </Link>
              ))}
            </div>
          </DataPanel>

          <DataPanel title={recentCatalyst}>
            <div className="report-list">
              {catalyst.slice(0, 8).map((report) => (
                <Link key={report.id} to={langSlug(report.fields?.slug || "/", lang)} className="report-list-item">
                  <span className="report-date">{report.fields?.date || "—"}</span>
                  <span className="report-title">
                    {report.fields?.inferredTitle || "Catalyst Report"}
                  </span>
                </Link>
              ))}
            </div>
          </DataPanel>
        </div>
      </div>
    </Layout>
  );
};

export default MarketsPage;

export const Head = ({ location }) => {
  const lang = location?.pathname?.startsWith("/en") ? "en" : "vi";
  return (
    <SEO
      title={lang === "vi" ? "Thị trường & Tình báo — Bobbie Intelligence" : "Markets & Intel — Bobbie Intelligence"}
      description={lang === "vi"
        ? "Tình báo thị trường crypto hàng ngày, tín hiệu vĩ mô và theo dõi biến động từ AI phân tích tự động."
        : "Daily crypto market intelligence, macro signals, and catalyst tracking from autonomous AI analysts."}
      path="/markets/"
      lang={lang}
    />
  );
};

export const query = graphql`
  query MarketsPage {
    allMarkdownRemark(
      filter: { fields: { category: { eq: "world-crypto" }, reportType: { eq: "daily" } } }
      sort: { fields: { date: DESC } }
      limit: 15
    ) {
      nodes {
        id
        html
        fields {
          slug
          date
          inferredTitle
          lang
          baseName
        }
      }
    }
    catalyst: allMarkdownRemark(
      filter: { fields: { category: { eq: "crypto-catalyst" } } }
      sort: { fields: { date: DESC } }
      limit: 12
    ) {
      nodes {
        id
        fields {
          slug
          date
          inferredTitle
          lang
          baseName
        }
      }
    }
  }
`;
